@keyframes slide-right-in {
  from { transform: translateX(100%); opacity: 0; }
  to   { transform: translateX(0);    opacity: 1; }
}
@keyframes slide-right-out {
  from { transform: translateX(0);     opacity: 1; }
  to   { transform: translateX(-100%); opacity: 0; }
}

html.slide-right::view-transition-new(root) {
  animation: slide-right-in 0.4s cubic-bezier(0.25,0.46,0.45,0.94) forwards;
}
html.slide-right::view-transition-old(root) {
  animation: slide-right-out 0.4s cubic-bezier(0.25,0.46,0.45,0.94) forwards;
}

import { TransitionLink } from "@/components/transition-link"
import "./transition.css"

export function SlideRightLink({ href, children, className }: {
  href: string
  children: React.ReactNode
  className?: string
}) {
  return (
    <TransitionLink
      href={href}
      transitionClass="slide-right"
      className={className}
    >
      {children}
    </TransitionLink>
  )
}

